export type PersonProfile = {
  id: string;
  name: string;
  wikipediaTitle?: string;
  introduction: string;
  history: string;
  attributes: string[];
  correctAttributes: string[];
  portraitUri?: string;
};

type HistoricalSeed = {
  id: string;
  name: string;
  wikipediaTitle?: string;
  role: string;
  knownFor: string;
  context: string;
  history: string;
};

const decoySets = [
  ["Court musician", "Mapmaker", "Medical herbalist"],
  ["Trade route organizer", "Religious reformer", "Textile artisan"],
  ["Military strategist", "Diplomatic envoy", "Agricultural reformer"],
  ["Legal advocate", "Ship navigator", "Poet and storyteller"],
  ["Printer and publisher", "Museum curator", "Architectural designer"]
];

function getPersonalityTraits(seed: HistoricalSeed, index: number): string[] {
  const profileText = `${seed.role} ${seed.knownFor} ${seed.context}`.toLowerCase();

  if (profileText.includes("activist") || profileText.includes("reform") || profileText.includes("rights") || profileText.includes("revolution")) {
    return ["Courageous under pressure", "Justice-minded"];
  }

  if (profileText.includes("scientist") || profileText.includes("mathematician") || profileText.includes("astronomer") || profileText.includes("physicist") || profileText.includes("chemist")) {
    return ["Highly observant", "Analytical thinker"];
  }

  if (profileText.includes("writer") || profileText.includes("poet") || profileText.includes("artist") || profileText.includes("composer") || profileText.includes("musician") || profileText.includes("painter")) {
    return ["Creative communicator", "Deeply expressive"];
  }

  if (profileText.includes("physician") || profileText.includes("nurse") || profileText.includes("medicine") || profileText.includes("health")) {
    return ["Service-minded", "Practical problem solver"];
  }

  if (profileText.includes("founder") || profileText.includes("leader") || profileText.includes("admiral") || profileText.includes("organizer")) {
    return ["Strategic thinker", "Persistent builder"];
  }

  const fallbackTraits = [
    ["Patient observer", "Independent thinker"],
    ["Steady under pressure", "Careful with details"],
    ["Curious learner", "Quietly determined"],
    ["Resourceful problem solver", "Focused on purpose"],
    ["Strong inner conviction", "Adaptable thinker"]
  ];

  return fallbackTraits[index % fallbackTraits.length];
}

function createProfile(seed: HistoricalSeed, index: number): PersonProfile {
  const correctAttributes = [...getPersonalityTraits(seed, index), seed.knownFor];
  return {
    id: seed.id,
    name: seed.name,
    wikipediaTitle: seed.wikipediaTitle || seed.name,
    introduction: "Take a quiet moment with this portrait. The name is hidden until the reveal, so notice which personality traits and life details feel true before you begin analyzing.",
    history: seed.history,
    correctAttributes,
    attributes: [...correctAttributes, ...decoySets[index % decoySets.length]]
  };
}

